-- Blog opening section under Key Takeaways must be EXACTLY 3 paragraphs:
-- P1: topical intro, P2: brand intro, P3: article preview ("In this blog, we'll examine...").

UPDATE guardrail_templates
SET template_content = E'## Key Takeaways\n\n- [Takeaway 1]\n- [Takeaway 2]\n- [Takeaway 3]\n\n(EXACTLY 3 bullets — no more, no less)\n\n## [H1 Topic — full title containing the primary keyword]\n\n[Paragraph 1 — Topical intro: define / describe the keyword topic, set context for the reader.]\n\n[Paragraph 2 — Brand intro: introduce the store and our offering as the trusted solution. Establish brand authority here.]\n\n[Paragraph 3 — Article preview starting with "In this blog, we''ll examine..." describing what sections follow.]\n\n(Opening section under Key Takeaways MUST be EXACTLY 3 paragraphs in this order — no more, no less)\n\n## [Major Section]\n\n[Bridge intro sentence (e.g. "Before X, understanding Y...") then content...]\n\n### [Subsection]\n\n[Content...]\n\n### [Subsection]\n\n[Content...]\n\n## [Next Major Section]\n\n[Repeat pattern: bridge sentence + 3-6 H3 subsections]\n\n## Frequently Asked Questions About [primary keyword]\n\n### [Question 1]\n\n[Answer]\n\n### [Question 2]\n\n[Answer]\n\n### [Question 3]\n\n[Answer]\n\n### [Question 4]\n\n[Answer]\n\n### [Question 5]\n\n[Answer]\n\n(EXACTLY 5 FAQ items, heading must be "Frequently Asked Questions About {primary keyword}")'
WHERE content_type = 'blog' AND field_name = 'structure';
